      docs: [
        "A MPC Execution Environment."
      ],
      type: {
        kind: "struct",
        fields: [
          {
            name: "_padding",
            docs: [
              "`cluster` used to be Option<u32>, so we need to add a padding byte for backwards",
              "compatibility."
            ],
            type: "u8"
          },
          {
            name: "cluster",
            docs: [
              "The cluster executing the MXE."
            ],
            type: "u32"
          },
          {
            name: "keygen_offset",
            docs: [
              "The offset used for the keygen computation account.",
              "Stored so requeue_mxe_keygen can find the computation account."
            ],
            type: "u64"
          },
          {
            name: "key_recovery_init_offset",
            docs: [
              "The offset used for the key recovery init computation account.",
              "Stored so queue_key_recovery_init can find the computation account."
            ],
            type: "u64"
          },
          {
            name: "mxe_program_id",
            docs: [
              "The program ID of the program that this MXE is associated with. Needed so that when we",
              "index this account offchain we can find out what program it is associated with."
            ],
            type: "pubkey"
          },
          {
            name: "authority",
            docs: [
              "The management authority of the MXE."
            ],
            type: {
              option: "pubkey"
            }
          },
          {
            name: "utility_pubkeys",
            docs: [
              "The utility pubkeys, consisting of",
              "- x25519 pubkey (32 bytes), used for key exchange",
              "- ed25519 verifying key (32 bytes), used for signature verification",
              "- ElGamal pubkey (32 bytes), used for c-spl",
              "- ElGamal pubkey validity proof (64 bytes), used for c-spl"
            ],
            type: {
              defined: {
                name: "SetUnset",
                generics: [
                  {
                    kind: "type",
                    type: {
                      defined: {
                        name: "UtilityPubkeys"
                      }
                    }
                  }
                ]
              }
            }
          },
          {
            name: "lut_offset_slot",
            type: "u64"
          },
          {
            name: "computation_definitions",
            docs: [
              "The offsets of all [ComputationDefinitionAccount]s of this MXE."
            ],
            type: {
              vec: "u32"
            }
          },
          {
            name: "status",
            docs: [
              "The status of this MXE (`Active` or `Migration`)."
            ],
            type: {
              defined: {
                name: "MxeStatus"
              }
            }
          },
          {
            name: "bump",
            docs: [
              "PDA bump. Declared by hand rather than via the `#[bump]` macro (which appends the bump",
              "as the *final* struct field) so it keeps its original offset right after `status`.",
              "The recovery-reward fields below are appended *after* the bump, leaving the byte layout",
              "of every field up to and including `bump` identical to the pre-staking `MXEAccount` \u2014",
              "old deserializers (including external user programs) decode the original prefix and",
              "harmlessly ignore the trailing fields."
            ],
            type: "u8"
          },
          {
            name: "current_epoch_recovery_rewards",
            docs: [
              "Running total of recovery-peer rewards accrued during `recovery_rewards_epoch`.",
              "Fed by the 20% slice of every computation/failure fee processed on this MXE;",
              "drained to zero by `claim_recovery_peer_fees` when recovery peers settle via",
              "`arcium_staking::finalize_recovery_epoch_rewards`. Same stale-epoch guard as",
              "`Cluster::current_epoch_total_rewards` \u2014 if peers don't settle before the epoch",
              "rolls over, new accruals are silently skipped until the pot is drained."
            ],
            type: "u64"
          },
          {
            name: "recovery_rewards_epoch",
            docs: [
              "Epoch that `current_epoch_recovery_rewards` is attributed to. Compared against the",
              "executing cluster's `last_updated_epoch` (the same proxy used by cluster rewards) to",
              "decide whether a new accrual is for the current round or a stale one."
            ],
            type: {
              defined: {
                name: "Epoch"
              }
            }
          }
        ]
      }
